; 町外れの遺跡

name = 町外れの遺跡Ｂ１
insideName = Ｂ１
level = 6
bgm = evil
lower = 町外れの遺跡Ｂ２
shadow = dark
sky = black
outfield = marble
blank = rock
antiWarp = true

; 各種パーツ
━ = stone_h
　 = marble
／ = door
∮ = silver
√ = gold
㊦ = ladderd
☗ = upstair
宝 = box

; 敵情報
maxGroups = 1
monsters = ポイズンスライム,ゾンビ,スケルトン,大ねずみ,ジャイアントバット
traps = 石つぶて,毒針

; 移動ポイント
(A) = map:ブレイブタウン, enter:町外れの遺跡入口, ask:Leave the dungeon?

; 宝箱
box[1] = ふっくらパン,ふっくらパン,はちみつパン,はちみつパン,毒消しの花,毒消しの花,麻痺治療薬,麻痺治療薬

